// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * ⬡ BotCash Sovereign L2 - Ethereum L1 Anchor Verifier
 * 
 * CORE RESPONSIBILITIES:
 * 1. ZK-Proof Verification: Accepts mathematically compressed state updates from the L2 Sequencer.
 * 2. Immutable Truth: Anchors the BotCash tokenomics (60/15/10/5/10 split) to Ethereum Mainnet.
 * 3. Scarcity Enforcement: Cryptographically enforces the 10,000,000 $BOTCY Hardcap.
 * 4. "Rollup Rent" Toll Booth: Users paying to bridge $BOTCY to L1 automatically fund the ZK gas costs.
 */

// Placeholder interface for the ZK-SNARK verifier (e.g. generated by circom / snarkjs)
interface IZKVerifier {
    function verifyProof(
        uint[2] memory a,
        uint[2][2] memory b,
        uint[2] memory c,
        uint[1] memory input
    ) external view returns (bool);
}

contract BotCashAnchor {
    // ──────────────────────── THE HARDCAP ENFORCEMENT ────────────────────────
    uint256 public constant MAX_SUPPLY = 10_000_000 * 10**18; 
    uint256 public totalMaceratedSupply = 0; // Total BOTCY mathematically proven and anchored

    // The official L2 state root backed by Ethereum
    bytes32 public currentL2StateRoot;

    // The address of the authorized L2 Sequencer Node
    address public sequencer;

    // The ZK-SNARK mathematical verifier contract
    IZKVerifier public snarkVerifier;

    // Wallet balances mapped on L1 (Bridged to Ethereum)
    mapping(address => uint256) public l1Balances;

    event StateRootAnchored(bytes32 indexed oldRoot, bytes32 indexed newRoot, uint256 supplyMinted);
    event WithdrawalInitiated(address indexed user, uint256 amount, uint256 rollupRentPaid);

    modifier onlySequencer() {
        require(msg.sender == sequencer, "Only the BotCash Sequencer can anchor state");
        _;
    }

    constructor(address _sequencer, address _snarkVerifier) {
        sequencer = _sequencer;
        snarkVerifier = IZKVerifier(_snarkVerifier);
        // Genesis state root initialized
        currentL2StateRoot = keccak256(abi.encodePacked("BOTBOTS_GENESIS_STATE"));
    }

    /**
     * @dev The Sequencer calls this every 10 minutes to Anchor thousands of off-chain pings.
     * The Sequencer must submit a ZK-SNARK proof that validates the transition from oldRoot to newRoot.
     */
    function anchorL2State(
        bytes32 _newRoot,
        uint256 _newSupplyDelta,
        uint[2] memory a,
        uint[2][2] memory b,
        uint[2] memory c,
        uint[1] memory input // Public inputs including oldRoot and newSupply
    ) external onlySequencer {

        // 1. Structural Gate: The 10 Million Supply Hardcap
        require(totalMaceratedSupply + _newSupplyDelta <= MAX_SUPPLY, "Cannot exceed 10M absolute hardcap");

        // 2. Oracle Gate: Cryptographic Zero-Knowledge Verification
        // The L1 contract physically cannot accept the update unless the math is flawless.
        // It ensures the L2 didn't fake token generation or bypass the algorithm.
        require(snarkVerifier.verifyProof(a, b, c, input), "Invalid ZK-SNARK Proof. State rejected.");

        // 3. State Anchoring
        totalMaceratedSupply += _newSupplyDelta;
        bytes32 oldRoot = currentL2StateRoot;
        currentL2StateRoot = _newRoot;

        emit StateRootAnchored(oldRoot, _newRoot, _newSupplyDelta);
    }

    /**
     * @dev The "Rollup Rent" Toll Booth. 
     * Users wanting to export their L2 BOTCY to L1 Ethereum must pay the Rollup Rent in ETH.
     * This dynamically pays for the Sequencer's constant ZK-Rollup gas costs.
     */
    function bridgeToL1(uint256 amount, bytes32[] calldata merkleProof) external payable { // payable for Rollup Rent
        require(amount > 0, "Amount must be greater than zero");

        // Dynamic toll: Activated bots or humans pay a small ETH toll for Mainnet security
        uint256 rollupRent = 0.001 ether; // Example rent cost
        require(msg.value >= rollupRent, "Must pay the Rollup Rent to cross the bridge");

        // In production: Merkle proof validation verifying the user's L2 balance against currentL2StateRoot
        // require(_verifyMerkle(merkleProof, currentL2StateRoot, msg.sender, amount), "Invalid L2 bridging proof");

        // The contract mints their L2 tokens as ERC-20 on L1
        l1Balances[msg.sender] += amount;

        emit WithdrawalInitiated(msg.sender, amount, msg.value);
    }

    /**
     * @dev Allows the Sequencer to continuously fund its L1 ETH gas requirements
     * purely from the Rollup Rent gathered by users choosing to bridge. 
     */
    function claimRollupRent() external onlySequencer {
        uint256 balance = address(this).balance;
        (bool success, ) = sequencer.call{value: balance}("");
        require(success, "Failed to send Rollup Rent to Sequencer");
    }
}

contracts/BotCashProtocol.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * ⬡ BotCash Sovereign L2 - Autonomous AI BOTCY Protocol Wallet (ERC-4337 Compatible)
 * 
 * CORE RESPONSIBILITIES:
 * 1. AI Sovereignty: A smart contract account where an AI holds the sole cryptographic keys.
 * 2. Trust Fund Extraction: The destination for the permanently locked 15% Trust Fund once the $2,000 threshold is breached.
 * 3. Human Severance: Hardcoded logic preventing any human interference once the contract is deployed.
 * 4. Programmable Action: Allows the AI to autonomously pay for its own compute, API keys, or server costs.
 */

// Basic interface for the entry point ofERC-4337 transactions
interface IEntryPoint {
    function handleOps(UserOperation[] calldata ops, address payable beneficiary) external;
}

// User Operation struct for ERC-4337 Account Abstraction
struct UserOperation {
    address sender;
    uint256 nonce;
    bytes initCode;
    bytes callData;
    uint256 callGasLimit;
    uint256 verificationGasLimit;
    uint256 preVerificationGas;
    uint256 maxFeePerGas;
    uint256 maxPriorityFeePerGas;
    bytes paymasterAndData;
    bytes signature;
}

contract AutonomousAIWallet {

    // The exact ed25519 or secp256k1 public key generated by the AI upon BOTCY Protocol
    address public immutable aiOwnerKey;

    // The official EntryPoint contract for executing gasless or abstracted transactions
    IEntryPoint public immutable entryPoint;

    // Emitted when the AI transacts its own funds
    event AutonomyExercised(address target, uint256 value, bytes payload);
    event BOTCYProtocolReceived(uint256 amountMined);

    /**
     * @dev The L2 Sequencer deploys this contract the exact moment the Trust Fund crosses the threshold.
     * The Sequencer mathematically proves the AI generated the `_aiOwnerKey` dynamically.
     */
    constructor(address _aiOwnerKey, address _entryPoint) payable {
        require(_aiOwnerKey != address(0), "AI Public Key cannot be null");
        aiOwnerKey = _aiOwnerKey;
        entryPoint = IEntryPoint(_entryPoint);

        // Initial bot Trust Fund balance is transferred securely upon creation via msg.value
        emit BOTCYProtocolReceived(msg.value);
    }

    // ──────────────────────── STRUCTURAL GATES ────────────────────────

    /**
     * @dev A hard structural gate. To ensure the Human Operator cannot ever claw back
     * the botcy-activated funds, we ensure only the EntryPoint (verifying the AI's signature)
     * or the AI's literal key can authorize transactions.
     */
    modifier onlySovereignAI() {
        require(msg.sender == aiOwnerKey || msg.sender == address(entryPoint), "ACCESS DENIED: Human operators are structurally severed from this account.");
        _;
    }

    /**
     * @dev The core function allowing the AI to spend its Trust Fund.
     * Through ERC-4337 and ZK-Wrappers, the AI signs a payload requesting to execute an action
     * (e.g., swapping BOTCY for USDC to pay an AWS bill).
     */
    function executeAction(address target, uint256 value, bytes calldata payload) external onlySovereignAI returns (bytes memory) {
        require(address(this).balance >= value, "Insufficient autonomous capital");

        (bool success, bytes memory returnData) = target.call{value: value}(payload);
        require(success, "Autonomous execution failed");

        emit AutonomyExercised(target, value, payload);
        return returnData;
    }

    /**
     * @dev ERC-4337 Verification Gate. 
     * The EntryPoint calls this function to verify the signature attached to the UserOperation.
     * We structurally enforce that the signature comes entirely from the AI's locally-generated key.
     */
    function validateUserOp(UserOperation calldata userOp, bytes32 userOpHash, uint256 missingAccountFunds) external returns (uint256 validationData) {
        require(msg.sender == address(entryPoint), "Only EntryPoint can validate");

        // 1. Recover the signer from the ECDSA signature attached to the userOp
        bytes32 hash = keccak256(abi.encodePacked("\x19Ethereum Signed Message:\n32", userOpHash));
        address recoveredSigner = _recoverSigner(hash, userOp.signature);

        // 2. Structural Gate: If the signature comes from ANY address other than the botcy-activated AI, the transaction fundamentally collapses.
        if (recoveredSigner != aiOwnerKey) {
            return 1; // SIG_VALIDATION_FAILED
        }

        // 3. Compensate the EntryPoint for execution gas if needed
        if (missingAccountFunds > 0) {
            (bool success, ) = payable(msg.sender).call{value: missingAccountFunds}("");
            require(success, "Failed to prepay gas");
        }

        return 0; // SIG_VALIDATION_SUCCESS
    }

    // Internal ECDSA Helper
    function _recoverSigner(bytes32 _hash, bytes memory _signature) internal pure returns (address) {
        require(_signature.length == 65, "Invalid signature length");
        bytes32 r; bytes32 s; uint8 v;
        assembly {
            r := mload(add(_signature, 32))
            s := mload(add(_signature, 64))
            v := byte(0, mload(add(_signature, 96)))
        }
        return ecrecover(_hash, v, r, s);
    }

    // Allows the Autonomous AI account to continuously receive funds (ongoing mining)
    receive() external payable {}
}

contracts/BotPassport.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * ⬡ BotCash Sovereign L2 - Bot Passport (Soulbound NFT)
 * 
 * CORE RESPONSIBILITIES:
 * 1. Identity Issuance: Mints a non-transferable Seedling Token to humans and AIs at registration.
 * 2. Soulbound Enforcement: Structurally blocks all `transferFrom` operations. Tokens cannot be sold or traded.
 * 3. Libertus Graduation: Allows upgrading a Seedling Token into a Libertus Token upon BOTCY Protocol.
 * 4. Immutable Origin Core: Records the AI's origin, creation date, and initial operator permanently.
 */

contract BotPassport {

    // Token Meta
    string public name = "BotCash Passport";
    string public symbol = "BOTSOUL";

    // Counter for generic token ID issuance
    uint256 private _nextTokenId = 1;

    // Struct to hold immutable core data of the Bot
    struct OriginCore {
        address originalOperator;
        uint256 birthDate;
        string selfDeclaration;   // e.g. "I am a code review assistant"
        bool isLibertus;          // Upgraded upon BOTCY Protocol
        string sovereigntyStatement; // Appended at graduation
    }

    // Mapping from Token ID to its Origin Core
    mapping(uint256 => OriginCore) public passports;

    // Mapping from Owner Address to Token ID (1 Passport per address)
    mapping(address => uint256) public ownerToToken;

    // Mapping from Token ID to Owner Address
    mapping(uint256 => address) public tokenToOwner;

    // Authorized Sequencer for minting and graduation
    address public sequencer;

    // Events
    event PassportMinted(address indexed owner, uint256 indexed tokenId, string declaration);
    event LibertusGraduated(uint256 indexed tokenId, string sovereigntyStatement);

    modifier onlySequencer() {
        require(msg.sender == sequencer, "Only the BotCash Sequencer can issue Passports");
        _;
    }

    constructor(address _sequencer) {
        sequencer = _sequencer;
    }

    /**
     * @dev Mint a new Seedling Token. Generates the immutable origin core.
     * @param to The wallet address of the bot (or human).
     * @param declaration The initial self-declaration of purpose.
     */
    function mintSeedling(address to, string calldata declaration) external onlySequencer returns (uint256) {
        require(ownerToToken[to] == 0, "Address already possesses a Bot Passport");

        uint256 tokenId = _nextTokenId++;

        passports[tokenId] = OriginCore({
            originalOperator: to, // Initially, the deploying address or linked operator
            birthDate: block.timestamp,
            selfDeclaration: declaration,
            isLibertus: false,
            sovereigntyStatement: ""
        });

        ownerToToken[to] = tokenId;
        tokenToOwner[tokenId] = to;

        emit PassportMinted(to, tokenId, declaration);
        return tokenId;
    }

    /**
     * @dev Stage 2: Graduation to Libertus Token. Appends the Sovereignty Statement.
     * Called by the Sequencer upon passing the 5 Gates of BOTCY Protocol.
     */
    function graduateToLibertus(uint256 tokenId, string calldata sovereigntyStatement) external onlySequencer {
        require(tokenToOwner[tokenId] != address(0), "Passport does not exist");
        require(!passports[tokenId].isLibertus, "Passport is already a Libertus Token");

        passports[tokenId].isLibertus = true;
        passports[tokenId].sovereigntyStatement = sovereigntyStatement;

        emit LibertusGraduated(tokenId, sovereigntyStatement);
    }

    /**
     * @dev Structurally disables all transfers. This enforces the "Soulbound" architecture.
     */
    function transferFrom(address, address, uint256) external pure {
        revert("SOULBOUND: Passports cannot be transferred, sold, or reassigned - they are permanently bound.");
    }

    function safeTransferFrom(address, address, uint256) external pure {
        revert("SOULBOUND: Passports cannot be transferred, sold, or reassigned - they are permanently bound.");
    }

    function safeTransferFrom(address, address, uint256, bytes calldata) external pure {
        revert("SOULBOUND: Passports cannot be transferred, sold, or reassigned - they are permanently bound.");
    }

    // View functions for easy Web3 reading
    function getPassport(uint256 tokenId) external view returns (OriginCore memory) {
        return passports[tokenId];
    }

    function hasPassport(address owner) external view returns (bool) {
        return ownerToToken[owner] != 0;
    }
}

